        (function() {
            const floatBtn = document.getElementById('mobileNavFloatingBtn');
            const overlay = document.getElementById('mobileRadialNavOverlay');
            const closeBtn = document.getElementById('radialNavCloseBtn');

            if (!floatBtn || !overlay || !closeBtn) return;

            // Open menu
            floatBtn.addEventListener('click', function(e) {
                e.stopPropagation();
                overlay.classList.add('active');
                document.body.style.overflow = 'hidden';
            });

            // Close menu function
            function closeMenu() {
                overlay.classList.remove('active');
                document.body.style.overflow = '';
            }

            // Close events
            closeBtn.addEventListener('click', function(e) {
                e.stopPropagation();
                closeMenu();
            });

            overlay.addEventListener('click', function(e) {
                if (e.target === overlay) {
                    closeMenu();
                }
            });

            // Auto-highlight active item based on current URL
            const currentUrl = window.location.href;
            const radialItems = overlay.querySelectorAll('.radial-item');
            let matchedAny = false;

            radialItems.forEach(item => {
                const href = item.href;
                if (href && href !== window.location.origin + '/' && currentUrl.startsWith(href.split('.html')[0])) {
                    item.classList.add('active');
                    matchedAny = true;
                } else {
                    item.classList.remove('active');
                }
            });

            if (!matchedAny) {
                const homeItem = overlay.querySelector('.radial-item:first-child');
                if (homeItem) homeItem.classList.add('active');
            }

            // Smooth scroll opacity effect for floating button
            let scrollTimer = null;
            window.addEventListener('scroll', function() {
                floatBtn.style.opacity = '0.4';
                if (scrollTimer !== null) {
                    clearTimeout(scrollTimer);
                }
                scrollTimer = setTimeout(function() {
                    floatBtn.style.opacity = '1.0';
                }, 1200);
            }, { passive: true });
        })();
        //
